plicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:14:\"Campus Connect\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:7:\"meetups\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:13:\"Student Clubs\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20458\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:366:\"WordPress Student Clubs are beginning to take shape as a new way to carry the momentum of WordPress Campus Connect beyond one-time workshops. What starts as an introduction to WordPress and open source is now continuing on campus through student-led groups that create space for learning, peer support, and early community participation. That shift matters [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:16634:\"\n<p class=\"wp-block-paragraph\">WordPress Student Clubs are beginning to take shape as a new way to carry the momentum of WordPress Campus Connect beyond one-time workshops. What starts as an introduction to WordPress and open source is now continuing on campus through student-led groups that create space for learning, peer support, and early community participation. That shift matters because it gives students a more consistent path into the WordPress ecosystem while helping local communities build stronger connections with the next generation of contributors.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" fetchpriority=\"high\" decoding=\"async\" width=\"1024\" height=\"768\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2025-11-24-16-36-20-1.jpg?resize=1024%2C768&#038;ssl=1\" alt=\"\" class=\"wp-image-20489\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2025-11-24-16-36-20-1.jpg?resize=1024%2C768&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2025-11-24-16-36-20-1.jpg?resize=300%2C225&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2025-11-24-16-36-20-1.jpg?resize=768%2C576&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2025-11-24-16-36-20-1.jpg?w=1280&amp;ssl=1 1280w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\"><em>Students showcasing a website they built during a club session</em></figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">When WordPress Campus Connect workshops first began reaching universities, the goal was straightforward: help students discover WordPress, understand the value of open source, and see that contribution can be part of their learning journey. In many cases, that first introduction created immediate interest. Students who had never worked with WordPress before started asking questions, exploring what the software could do, and showing curiosity about the wider community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That early response also revealed a gap. A workshop could spark interest, but it could not always sustain it on its own. Encouraging students to attend local WordPress meetups helped extend that first connection and, in some cases, brought new energy to existing local communities. Even so, it became clear that campuses needed something more consistent and closer to students’ everyday environment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress Student Clubs emerged from that need. Instead of limiting engagement to a single event, these clubs create an ongoing, student-led presence on campus where students can keep learning, share knowledge with peers, and grow more confident over time. They also offer a practical bridge between first exposure and deeper participation, helping students move from curiosity to contribution through regular activity and community support.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Learning What Sustains Participation</h2>\n\n\n\n<p class=\"wp-block-paragraph\">As WordPress Student Clubs started forming across campuses, the early enthusiasm was encouraging, but sustaining that momentum proved to be one of the first real challenges. Student Club Organizers shared that interest was often strongest at the beginning, especially after a workshop or an introductory session, but turning that interest into regular participation required patience and experimentation. Like many community efforts, the clubs needed time to find a rhythm that worked for the students involved.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One of the most common challenges was consistency. Many students were interested in learning WordPress, but regular engagement depended on more than initial curiosity. Organizers found that participation grew more steadily when activities felt approachable and useful, especially when students could learn by doing rather than only listening. Small learning sessions, collaborative exercises, and hands-on activities often made it easier for students to return and take part again.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Organizers also noticed that some students were initially hesitant to engage actively. Asking questions, speaking up in a group, or volunteering to help lead a session did not always happen naturally. Building a club meant creating an environment where students felt comfortable enough to participate, try something new, and gradually take ownership of their own learning.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Academic schedules added another layer of complexity. Because the clubs are student-led, planning around classes, assignments, and exams required flexibility. Keeping activities regular without overwhelming organizers or participants meant working within the rhythms of campus life. Those early difficulties became part of the learning process and helped shape how the clubs began to operate more effectively.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Building Through Small, Consistent Activities</h2>\n\n\n\n<p class=\"wp-block-paragraph\">As organizers worked through those challenges, certain approaches began to show results. Instead of focusing on large events, many clubs found momentum through simple, repeatable activities that students could join without feeling intimidated. Regular learning sessions, small hands-on workshops, and peer-to-peer discussions helped create an environment that felt both welcoming and practical.<br></p>\n\n\n\n<figure class=\"wp-block-image aligncenter size-large\"><img data-recalc-dims=\"1\" decoding=\"async\" width=\"1024\" height=\"575\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/image.png?resize=1024%2C575&#038;ssl=1\" alt=\"\" class=\"wp-image-20467\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/image.png?resize=1024%2C575&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/image.png?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/image.png?resize=768%2C431&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/04/image.png?w=1280&amp;ssl=1 1280w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\"><em>A Student club activity in a college led by a student club Organizer</em></figcaption></figure>\n\n\n\n<div class=\"wp-block-group is-layout-constrained wp-block-group-is-layout-constrained\">\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" decoding=\"async\" width=\"1024\" height=\"768\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-03.jpg?resize=1024%2C768&#038;ssl=1\" alt=\"\" class=\"wp-image-20468\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-03.jpg?resize=1024%2C768&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-03.jpg?resize=300%2C225&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-03.jpg?resize=768%2C576&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-03.jpg?resize=1536%2C1152&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-03.jpg?w=1600&amp;ssl=1 1600w\" sizes=\"(max-width: 1000px) 100vw, 1000px\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"768\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-06.jpg?resize=1024%2C768&#038;ssl=1\" alt=\"\" class=\"wp-image-20469\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-06.jpg?resize=1024%2C768&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-06.jpg?resize=300%2C225&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-06.jpg?resize=768%2C576&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-06.jpg?resize=1536%2C1152&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2026/04/PHOTO-2026-02-25-23-25-06.jpg?w=1600&amp;ssl=1 1600w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\"><em>Students showcasing websites built during a club session</em></figcaption></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">That steady approach mattered. When students could return to familiar formats and see progress from one session to the next, clubs became easier to sustain. Organizers were able to build routines, and participants could join at their own pace. Over time, those small efforts started to strengthen participation more effectively than occasional large events.</p>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Student ownership also played an important role. As students began sharing what they had learned, helping their peers, and taking part in running sessions, engagement started to grow more organically. These moments helped shift the clubs from being simply learning spaces to becoming communities in their own right. Students were not only using WordPress in a classroom context. They were also beginning to understand it as part of a collaborative open source project shaped by people who learn together, build together, and support one another.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Guidance from the local WordPress community helped reinforce that progress. Although the clubs are student-led, organizers benefited from having experienced community members available as mentors. Mentors helped them think through session structure, activity planning, and the practical challenge of staying motivated while balancing academic responsibilities. That kind of support gave organizers more confidence to experiment and keep building.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Mentorship also connected campus activity to the broader WordPress ecosystem. Students were not learning in isolation. Through local community guidance, they were able to see how meetups, contributions, and collaboration all fit into a larger network of people who have been participating in WordPress for years. That connection gave the work happening on campus greater meaning and helped students see a clearer path forward.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Early Impact Across Campuses</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Although WordPress Student Clubs are still in an early stage, signs of impact are already visible. Organizers have shared that more students are showing interest in learning WordPress and in exploring what open source participation can look like in practice. In several cases, students who first joined as learners are now contributing to discussions, helping peers during sessions, and organizing club activities themselves.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That shift from passive participation to active involvement is one of the clearest signs of growth. It suggests that the clubs are beginning to create more than awareness. They are creating opportunities for students to build confidence, practice leadership, and develop a stronger sense of connection to the WordPress community. Even at this stage, that kind of change points to the long-term value of sustaining engagement on campus.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One encouraging example came during the International Women’s Day celebration in Ajmer, India, where students participated alongside members of the local WordPress community. Organizers noted that the event included 100 female attendees, with around 50% of participants coming from student clubs. For many of those students, it was a first opportunity to take part in a broader community event, meet other contributors, and see how open source communities collaborate in practice.</p>\n\n\n\n<figure class=\"wp-block-image aligncenter size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"768\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-22-at-5.08.47-pm.png?resize=1024%2C768&#038;ssl=1\" alt=\"\" class=\"wp-image-20463\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-22-at-5.08.47-pm.png?resize=1024%2C768&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-22-at-5.08.47-pm.png?resize=300%2C225&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-22-at-5.08.47-pm.png?resize=768%2C576&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-22-at-5.08.47-pm.png?resize=1536%2C1152&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-22-at-5.08.47-pm.png?resize=2048%2C1536&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\"><em>Women’s Day Ajmer 2026 Event, where more than 50% participation from student clubs</em></figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Experiences like that show how student-led initiatives can extend beyond campus and begin contributing to the wider community. They also create space for new voices to participate. As students move from club sessions into local events, they gain experience not only as learners but also as community members who can help shape what comes next.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The clubs are also creating leadership opportunities on campus. Organizers have stepped into new roles by coordinating activities, encouraging participation, and maintaining momentum over time. Those experiences help students build skills that matter both within the WordPress community and beyond it, including communication, organization, and problem-solving.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">“Being a Student Club Organizer helped me improve my leadership and communication skills.”<br><em>— Sanjeevni Kumari, WordPress Student Club Organizer, Mahila Engineering College, Ajmer</em></p>\n</blockquote>\n\n\n\n<h2 class=\"wp-block-heading\">Looking Ahead</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress Student Clubs are still developing, but the journey so far points to a promising direction. What began as an effort to sustain interest after WordPress Campus Connect is gradually becoming a more durable model for ongoing learning and collaboration on campus. The clubs are helping students stay connected to WordPress beyond a first introduction, while also creating stronger links between educational spaces and local communities.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That longer-term potential is one reason this work matters. With regular campus activity and continued mentorship, Student Clubs can help create a stronger foundation for future contributors. They can also help students build confidence before attending local meetups, contributing to community efforts, or participating in events beyond their campuses.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">“With regular on-campus activities through WordPress Student Clubs, the real impact may become visible over the next couple of years, as a stronger WordPress ecosystem begins to take shape within campuses.”<br><em>— Anand Upadhyay, Student Club Mentor</em></p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">As more students get involved and take ownership of these spaces, WordPress Student Clubs can continue to open pathways to learning, leadership, and community participation. For campuses, they offer a way to keep the momentum going after Campus Connect. For the broader project, they represent another step toward welcoming more students into the WordPress open source ecosystem. To follow this work and explore how it connects with the wider community, readers can look to <a href=\"https://wordpress.org/education/campus-connect/\">WordPress Campus Connect</a>, <a href=\"https://events.wordpress.org/\">WordPress Meetups</a>, and other education and community initiatives across WordPress.org.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em><strong>Note:&nbsp;</strong>Much of the credit belongs to&nbsp;<a href=\"https://profiles.wordpress.org/webtechpooja/\">@webtechpooja</a>&nbsp;(<a href=\"https://profiles.wordpress.org/webtechpooja/\">Pooja Derashri</a>) for help in writing this piece.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"20458\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"Celebrating Community at WordCamp Asia 2026\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://wordpress.org/news/2026/04/celebrating-wcasia-2026/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 11 Apr 2026 18:21:14 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:9:\"Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20385\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:395:\"WordCamp Asia 2026 brought the global WordPress community to Mumbai, India, from April 9–11, gathering contributors, organizers, sponsors, speakers, and attendees at the Jio World Convention Centre for three days of learning, collaboration, and community. With 2,627 attendees, the event reflected the scale of the WordPress community and the strong turnout throughout the event. The [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:64500:\"\n<p class=\"wp-block-paragraph\">WordCamp Asia 2026 brought the global WordPress community to Mumbai, India, from April 9–11, gathering contributors, organizers, sponsors, speakers, and attendees at the Jio World Convention Centre for three days of learning, collaboration, and community. With 2,627 attendees, the event reflected the scale of the WordPress community and the strong turnout throughout the event.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The event unfolded across Contributor Day and two conference days, with a program that moved from technical sessions and workshops to hallway conversations, shared meals, and joyful moments of connection across the venue. From first-time attendees to longtime contributors, WordCamp Asia 2026 reflected the breadth of the WordPress ecosystem and the many ways people shaped and sustained it.</p>\n\n\n\n<div class=\"wp-block-group is-nowrap is-layout-flex wp-container-core-group-is-layout-7387b849 wp-block-group-is-layout-flex\">\n<figure class=\"wp-block-pullquote\"><blockquote><p><mark style=\"background-color:#2f363d;color:#cf2e2e\" class=\"has-inline-color\"><br></mark>WordPress is not a company. It is a shared commitment to keeping the web open.</p><cite>Mary Hubbard, Executive Director, WordPress</cite></blockquote></figure>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Throughout the event, WordCamp Asia 2026 balanced formal programming with the conversations happening around it. Sessions and workshops set the pace, while morning networking, tea breaks, lunch, the family photo, the sponsor’s raffle, and the after party in Jasmine Hall helped make the event feel welcoming, social, and connected.<br></p>\n\n\n\n<h2 class=\"wp-block-heading\">How WordCamp Asia 2026 Took Shape</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Bringing together contribution, practical learning, and forward-looking conversation in one shared program. Across Contributor Day and the conference sessions that followed, attendees moved between hands-on work, technical talks, workshops, and broader discussions about AI, education, enterprise, community growth, and the open web.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The result was a WordCamp that felt expansive without losing its sense of connection. Different rooms with topics as themes, helping different audiences, and different forms of participation all fed into the same larger picture: a community actively building what comes next for WordPress as a feeling that something bigger was happening: not just a schedule being delivered, but a community showing up for one another and for the future of WordPress.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Contributor Day: Building WordPress Together</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Contributor Day opened WordCamp Asia 2026 with one of the clearest expressions of what makes the project special: people coming together to move WordPress forward by working on it. More than 1,500 participants joined 38 table leads across more than 20 contribution tables, creating a day that was expansive in scale and grounded in real work. For some, it was a return to familiar teams and longtime collaborators. For others, it was the beginning of their contributor journey.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The day moved between structured learning and hands-on participation. Alongside contributor sessions, attendees joined workshops, visited the <a href=\"https://asia.wordcamp.org/2026/contributor-day/open-source-library/\">Open Source Library</a>, took part in <a href=\"https://asia.wordcamp.org/2026/youthcamp-is-back-at-wordcamp-asia-2026/\">YouthCamp</a>, and attended <em>The Making of a WordPress Release: Conversations with Past Release Squad Members</em>, a featured panel that added depth and perspective to the work of building and sustaining WordPress.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" class=\"youtube-player\" width=\"600\" height=\"338\" src=\"https://www.youtube.com/embed/BFxdBBxd_Wc?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=en-US&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation allow-popups-to-escape-sandbox\"></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">What made Contributor Day stand out was not only the number of people in the room, but the range of ways they could take part. Workshops created space for skill-building. YouthCamp brought younger participants into the experience and widened the event’s reach in a meaningful way. The day felt welcoming, energetic, and full of possibility.</p>\n\n\n\n<p class=\"wp-block-paragraph\">By the end, the impact was already visible across teams. Polyglots contributors suggested more than 7,000 strings and reviewed 3,200 of them. Photo contributors uploaded 76 images. The Test team worked on more than 20 tickets, and 55 contributors joined Training. Those numbers told only part of the story, but they pointed to what Contributor Day continued to do so well: turn a large gathering into shared work that strengthened the project in real time.</p>\n\n\n\n<figure data-wp-context=\"{&quot;galleryId&quot;:&quot;69f863b761434&quot;}\" data-wp-interactive=\"core/gallery\" class=\"wp-block-gallery has-nested-images columns-default is-cropped has-black-background-color has-background wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\" style=\"border-width:20px;border-radius:2px\">\n<figure data-wp-context=\"{&quot;imageId&quot;:&quot;69f863b761b25&quot;}\" data-wp-interactive=\"core/image\" data-wp-key=\"69f863b761b25\" class=\"wp-block-image size-large wp-lightbox-container\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"683\" height=\"1024\" data-wp-class--hide=\"state.isContentHidden\" data-wp-class--show=\"state.isContentVisible\" data-wp-init=\"callbacks.setButtonStyles\" data-wp-on--click=\"actions.showLightbox\" data-wp-on--load=\"callbacks.setButtonStyles\" data-wp-on--pointerdown=\"actions.preloadImage\" data-wp-on--pointerenter=\"actions.preloadImageWithDelay\" data-wp-on--pointerleave=\"actions.cancelPreload\" data-wp-on-window--resize=\"callbacks.setButtonStyles\" data-id=\"20392\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSC08818.jpg?resize=683%2C1024&#038;ssl=1\" alt=\"\" class=\"wp-image-20392\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/DSC08818-scaled.jpg?resize=68